using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capabilities to the research agent.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Search the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        [Description("Maximum number of results to return (1-5)")] int maxResults = 3,
        CancellationToken cancellationToken = default)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(query);
        maxResults = Math.Clamp(maxResults, 1, 5);

        try
        {
            // Use DuckDuckGo Instant Answer API (no API key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            using var response = await _httpClient.GetAsync(url, cancellationToken);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadAsStringAsync(cancellationToken);
            var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<SearchResult>();

            // Extract abstract if available
            if (root.TryGetProperty("Abstract", out var abstractEl) &&
                abstractEl.GetString() is { Length: > 0 } abstractText)
            {
                var source = root.TryGetProperty("AbstractSource", out var src) ? src.GetString() ?? "" : "";
                var abstractUrl = root.TryGetProperty("AbstractURL", out var aUrl) ? aUrl.GetString() ?? "" : "";
                results.Add(new SearchResult($"{source} - Summary", abstractText, abstractUrl));
            }

            // Extract related topics
            if (root.TryGetProperty("RelatedTopics", out var topics) &&
                topics.ValueKind == JsonValueKind.Array)
            {
                foreach (var topic in topics.EnumerateArray())
                {
                    if (results.Count >= maxResults) break;

                    if (topic.TryGetProperty("Text", out var text) &&
                        text.GetString() is { Length: > 0 } topicText)
                    {
                        var topicUrl = topic.TryGetProperty("FirstURL", out var fUrl) ? fUrl.GetString() ?? "" : "";
                        var title = topicText.Length > 80 ? topicText[..80] + "..." : topicText;
                        results.Add(new SearchResult(title, topicText, topicUrl));
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No results found for '{query}'. Try rephrasing the search query.";
            }

            return JsonSerializer.Serialize(results, JsonContext.Default.ListSearchResult);
        }
        catch (HttpRequestException ex)
        {
            return $"Search failed: {ex.Message}. Please try a different query.";
        }
    }

    [Description("Fetch and read the content of a specific web page URL. Returns the text content of the page.")]
    public async Task<string> ReadWebPageAsync(
        [Description("The URL of the web page to read")] string url,
        [Description("Maximum number of characters to return")] int maxLength = 2000,
        CancellationToken cancellationToken = default)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(url);
        maxLength = Math.Clamp(maxLength, 500, 5000);

        try
        {
            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri) ||
                (uri.Scheme != "http" && uri.Scheme != "https"))
            {
                return "Invalid URL. Please provide a valid HTTP or HTTPS URL.";
            }

            using var request = new HttpRequestMessage(HttpMethod.Get, uri);
            request.Headers.Add("User-Agent", "ResearchAgent/1.0");

            using var response = await _httpClient.GetAsync(uri, cancellationToken);
            response.EnsureSuccessStatusCode();

            var content = await response.Content.ReadAsStringAsync(cancellationToken);

            // Simple HTML to text conversion: strip tags
            var text = StripHtml(content);
            if (text.Length > maxLength)
            {
                text = text[..maxLength] + "\n... [content truncated]";
            }

            return string.IsNullOrWhiteSpace(text)
                ? "The page content could not be extracted."
                : text;
        }
        catch (HttpRequestException ex)
        {
            return $"Failed to read page: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        // Remove script and style blocks
        var text = System.Text.RegularExpressions.Regex.Replace(
            html, @"<(script|style)[^>]*>.*?</\1>", "", System.Text.RegularExpressions.RegexOptions.Singleline);
        // Remove tags
        text = System.Text.RegularExpressions.Regex.Replace(text, @"<[^>]+>", " ");
        // Collapse whitespace
        text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ");
        return text.Trim();
    }
}

public record SearchResult(string Title, string Snippet, string Url);

[System.Text.Json.Serialization.JsonSerializable(typeof(List<SearchResult>))]
internal partial class JsonContext : System.Text.Json.Serialization.JsonSerializerContext;

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent to organize findings.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];
    private readonly Lock _lock = new();

    [Description("Save a research note with a title and content. Use this to record key findings during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content/body of the note with the research finding")] string content,
        [Description("Optional source URL where this information was found")] string? sourceUrl = null)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(title);
        ArgumentException.ThrowIfNullOrWhiteSpace(content);

        lock (_lock)
        {
            var note = new ResearchNote(
                Id: _notes.Count + 1,
                Title: title,
                Content: content,
                SourceUrl: sourceUrl,
                CreatedAt: DateTime.UtcNow);
            _notes.Add(note);
            return $"Note #{note.Id} saved: '{title}'";
        }
    }

    [Description("List all saved research notes. Returns titles and IDs of all notes taken so far.")]
    public string ListNotes()
    {
        lock (_lock)
        {
            if (_notes.Count == 0)
            {
                return "No notes saved yet.";
            }

            var sb = new StringBuilder();
            sb.AppendLine($"Research Notes ({_notes.Count} total):");
            foreach (var note in _notes)
            {
                var source = note.SourceUrl is not null ? $" [source: {note.SourceUrl}]" : "";
                sb.AppendLine($"  #{note.Id}: {note.Title}{source}");
            }
            return sb.ToString();
        }
    }

    [Description("Get the full content of a specific note by its ID.")]
    public string GetNote([Description("The numeric ID of the note to retrieve")] int noteId)
    {
        lock (_lock)
        {
            if (noteId < 1 || noteId > _notes.Count)
            {
                return $"Note #{noteId} not found. Use ListNotes to see available notes.";
            }

            var note = _notes[noteId - 1];
            var sb = new StringBuilder();
            sb.AppendLine($"Note #{note.Id}: {note.Title}");
            sb.AppendLine($"Created: {note.CreatedAt:u}");
            if (note.SourceUrl is not null)
                sb.AppendLine($"Source: {note.SourceUrl}");
            sb.AppendLine("---");
            sb.AppendLine(note.Content);
            return sb.ToString();
        }
    }

    [Description("Get all notes as a formatted research summary, suitable for compiling a final report.")]
    public string GetAllNotesForSummary()
    {
        lock (_lock)
        {
            if (_notes.Count == 0)
            {
                return "No notes have been saved. Conduct some research first.";
            }

            var sb = new StringBuilder();
            sb.AppendLine("=== RESEARCH NOTES COMPILATION ===");
            sb.AppendLine();
            foreach (var note in _notes)
            {
                sb.AppendLine($"## {note.Title}");
                if (note.SourceUrl is not null)
                    sb.AppendLine($"Source: {note.SourceUrl}");
                sb.AppendLine(note.Content);
                sb.AppendLine();
            }
            return sb.ToString();
        }
    }
}

public record ResearchNote(int Id, string Title, string Content, string? SourceUrl, DateTime CreatedAt);

