using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

// Configure logging
builder.Logging.SetMinimumLevel(LogLevel.Warning);

// Register HttpClient
builder.Services.AddHttpClient();

// Register the chat client via MEAI abstraction
var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the AI:ApiKey configuration or OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(chatClientBuilder => chatClientBuilder
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

using var host = builder.Build();

// Resolve services
var chatClient = host.Services.GetRequiredService<IChatClient>();
var httpClientFactory = host.Services.GetRequiredService<IHttpClientFactory>();
var loggerFactory = host.Services.GetRequiredService<ILoggerFactory>();

// Create tool instances
var httpClient = httpClientFactory.CreateClient();
httpClient.Timeout = TimeSpan.FromSeconds(15);
var webSearch = new WebSearchTool(httpClient);
var noteTaking = new NoteTakingTool();

// Define tools for the agent
var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(webSearch.ReadWebPageAsync),
    AIFunctionFactory.Create(noteTaking.SaveNote),
    AIFunctionFactory.Create(noteTaking.ListNotes),
    AIFunctionFactory.Create(noteTaking.GetNote),
    AIFunctionFactory.Create(noteTaking.GetAllNotesForSummary),
};

const string SystemPrompt = """
    You are a research agent. Your job is to thoroughly research a topic provided by the user.

    Follow this process:
    1. Search the web for relevant information on the topic using multiple search queries.
    2. Read promising web pages to gather detailed information.
    3. Save key findings as notes, including the source URL.
    4. After gathering sufficient information (at least 3 notes), compile all notes and
       produce a well-structured summary of your findings.

    Always cite your sources. Be thorough but concise in your final summary.
    """;

// Create the agent using Microsoft Agent Framework
var agent = new ChatClientAgent(
    chatClient,
    instructions: SystemPrompt,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes",
    tools: tools,
    loggerFactory: loggerFactory);

// Get the research topic
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a topic to research: ");
    topic = Console.ReadLine()?.Trim() ?? "";
}

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("Error: No topic provided.");
    return 1;
}

Console.WriteLine($"\nResearching: {topic}");
Console.WriteLine("Working...\n");

// Run the agent with iteration limit for cost control
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(
    $"Research this topic and provide a comprehensive summary: {topic}",
    options: runOptions);

// Output the final response
Console.WriteLine("═══════════════ RESEARCH RESULTS ═══════════════\n");

foreach (var message in response.Messages)
{
    if (message.Role == ChatRole.Assistant && message.Text is { Length: > 0 } text)
    {
        Console.WriteLine(text);
    }
}

Console.WriteLine("\n═════════════════════════════════════════════════");
return 0;

